from flask import Flask, render_template, redirect, url_for, request, session, flash
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
from functools import wraps
from datetime import timedelta

app = Flask(__name__)
app.secret_key = "secretkey"

# Database Setup (For simplicity, we use a dictionary)
users = {
    'user1': generate_password_hash('password'),
    'mfa_secret': pyotp.random_base32()
}

# Login endpoint
@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        if username in users and check_password_hash(users[username], password):
            session['logged_in'] = True
            session['username'] = username
            # Redirect to MFA verification endpoint
            return redirect(url_for('verify_mfa'))
    return render_template('login.html')

# MFA Verification endpoint
@app.route('/verify-mfa', methods=['GET'])
def verify_mfa():
    if 'logged_in' in session:
        # Generate QR code or display secret key for user to enter TOTP
        mfa_secret = users['mfa_secret']
        return render_template('verify_mfa.html', mfa_secret=mfa_secret)
    else:
        flash('You must be logged in to verify MFA')
        return redirect(url_for('login'))

# Background check for MFA verification
def requires_mfa(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'logged_in' not in session or 'mfa_verified' not in session:
            return redirect(url_for('verify_mfa'))
        return f(*args, **kwargs)
    return decorated_function

# Protected endpoint
@app.route('/protected')
@requires_mfa
def protected():
    # User has MFA verified and is logged in
    if 'logged_in' in session and session['mfa_verified']:
        return render_template('protected.html', username=session['username'])
    else:
        flash('You must be logged in to access this page')
        return redirect(url_for('login'))

